-- Add Unsplash images to existing blog articles
UPDATE public.blog_posts SET content = REGEXP_REPLACE(content, '(<p>Did you know)', '<img src="https://source.unsplash.com/800x400/?resume,office,professional" alt="Professional resume on desk" class="rounded-xl shadow-md w-full" loading="lazy" /><p></p>$1') WHERE slug = 'ats-friendly-resume-guide' AND content NOT LIKE '%unsplash%';
UPDATE public.blog_posts SET content = REGEXP_REPLACE(content, '(<p>Recruiters spend)', '<img src="https://source.unsplash.com/800x400/?interview,hiring,recruiter" alt="Job interview preparation" class="rounded-xl shadow-md w-full" loading="lazy" /><p></p>$1') WHERE slug = 'resume-mistakes-to-avoid' AND content NOT LIKE '%unsplash%';
UPDATE public.blog_posts SET content = REGEXP_REPLACE(content, '(<p>Keywords are the bridge)', '<img src="https://source.unsplash.com/800x400/?keywords,search,technology" alt="Search and keywords concept" class="rounded-xl shadow-md w-full" loading="lazy" /><p></p>$1') WHERE slug = 'resume-keywords-by-industry' AND content NOT LIKE '%unsplash%';
UPDATE public.blog_posts SET content = REGEXP_REPLACE(content, '(<p>You need a great)', '<img src="https://source.unsplash.com/800x400/?resume,computer,writing" alt="Building resume on computer" class="rounded-xl shadow-md w-full" loading="lazy" /><p></p>$1') WHERE slug = 'free-vs-paid-resume-builders' AND content NOT LIKE '%unsplash%';
UPDATE public.blog_posts SET content = REGEXP_REPLACE(content, '(<p>Changing careers is)', '<img src="https://source.unsplash.com/800x400/?career,change,success" alt="Career change and new beginnings" class="rounded-xl shadow-md w-full" loading="lazy" /><p></p>$1') WHERE slug = 'career-change-resume-guide' AND content NOT LIKE '%unsplash%';
